using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.GeneralSettings;using verii_metivon_api.Modules.Procurement.Application.Services;using verii_metivon_api.Modules.Procurement.Domain.Entities;using verii_metivon_api.Modules.Procurement.Domain.Enums;
namespace verii_metivon_api.Modules.Procurement.Api;
[ApiController,Authorize,Route("api/purchase-orders")]public sealed class PurchaseOrdersController(IPurchaseOrderService service,MetivonDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List([FromQuery]PurchaseOrderQuery q,CancellationToken ct){var r=await service.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}
[HttpGet("{id:long}")]public async Task<IActionResult>Get(long id,CancellationToken ct){var e=await db.PurchaseOrders.AsNoTracking().Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Purchase order not found.",404));return Ok(ApiResponse<object>.Ok(new{e.OrderNumber,e.OrderType,e.BranchId,e.SupplierId,e.TradeDossierId,e.CurrencyId,e.PaymentTermId,e.WarehouseId,e.OrderDate,e.RequestedDeliveryDate,e.SupplierReference,e.BuyerNote,e.ExchangeRate,Lines=e.Lines.OrderBy(x=>x.LineNumber).Select(x=>new{x.ProductId,x.UnitId,x.StorageLocationId,x.Description,Quantity=x.OrderedQuantity,x.UnitPrice,x.DiscountRate,x.TaxRate,x.RequestedDeliveryDate,x.OverDeliveryTolerance,x.UnderDeliveryTolerance})}));}
[HttpPost]public async Task<IActionResult>Create(CreatePurchaseOrderRequest x,CancellationToken ct){var r=await service.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}
[HttpPut("{id:long}")]public async Task<IActionResult>Update(long id,CreatePurchaseOrderRequest r,CancellationToken ct){var e=await db.PurchaseOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Purchase order not found.",404));if(e.Status!=PurchaseOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft purchase orders can be edited.",409));if(r.Lines.Count==0)return BadRequest(ApiResponse<object>.Error("At least one line is required.",400));if(await db.PurchaseOrders.AnyAsync(x=>x.Id!=id&&x.OrderNumber==(string.IsNullOrWhiteSpace(r.OrderNumber)?e.OrderNumber:r.OrderNumber.Trim().ToUpperInvariant()),ct))return Conflict(ApiResponse<object>.Error("Order number already exists.",409));var currency=await db.Currencies.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.CurrencyId&&x.IsActive,ct);if(currency is null)return BadRequest(ApiResponse<object>.Error("An active currency is required.",400));var baseCurrencyId=await db.Set<GeneralSetting>().AsNoTracking().Where(x=>x.ScopeKey=="GLOBAL").Select(x=>(long?)x.DefaultCurrencyId).FirstOrDefaultAsync(ct)??await db.Currencies.AsNoTracking().Where(x=>x.IsActive&&x.IsDefault).Select(x=>(long?)x.Id).FirstOrDefaultAsync(ct);var effectiveExchangeRate=baseCurrencyId==currency.Id?1m:r.ExchangeRate;if(effectiveExchangeRate<=0)return BadRequest(ApiResponse<object>.Error("A positive exchange rate is required.",400));if(r.TradeDossierId.HasValue){var trade=await db.TradeDossiers.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.TradeDossierId.Value,ct);if(trade is null||trade.CurrencyId!=r.CurrencyId||trade.BranchId!=r.BranchId||trade.BusinessPartnerId!=r.SupplierId)return Conflict(ApiResponse<object>.Error("Trade dossier, branch, supplier and currency must match the purchase order.",409));}e.OrderNumber=string.IsNullOrWhiteSpace(r.OrderNumber)?e.OrderNumber:r.OrderNumber.Trim().ToUpperInvariant();e.OrderType=r.OrderType;e.BranchId=r.BranchId;e.SupplierId=r.SupplierId;e.TradeDossierId=r.TradeDossierId;e.CurrencyId=r.CurrencyId;e.PaymentTermId=r.PaymentTermId;e.WarehouseId=r.WarehouseId;e.OrderDate=r.OrderDate;e.RequestedDeliveryDate=r.RequestedDeliveryDate;e.SupplierReference=r.SupplierReference?.Trim();e.BuyerNote=r.BuyerNote?.Trim();e.ExchangeRate=effectiveExchangeRate;db.PurchaseOrderLines.RemoveRange(e.Lines);e.Lines=[];e.Subtotal=e.DiscountTotal=e.TaxTotal=e.GrandTotal=0;var n=0;foreach(var l in r.Lines){if(l.Quantity<=0||l.UnitPrice<0)return BadRequest(ApiResponse<object>.Error("Line quantity and price are invalid.",400));var amounts=PurchaseOrderAmountCalculator.Calculate(l.Quantity,l.UnitPrice,l.DiscountRate,l.TaxRate);e.Lines.Add(new PurchaseOrderLine{LineNumber=++n,ProductId=l.ProductId,UnitId=l.UnitId,StorageLocationId=l.StorageLocationId,Description=l.Description?.Trim(),OrderedQuantity=l.Quantity,UnitPrice=l.UnitPrice,DiscountRate=l.DiscountRate,DiscountAmount=amounts.DiscountAmount,TaxRate=l.TaxRate,TaxAmount=amounts.TaxAmount,LineTotal=amounts.GrandTotal,RequestedDeliveryDate=l.RequestedDeliveryDate,OverDeliveryTolerance=l.OverDeliveryTolerance,UnderDeliveryTolerance=l.UnderDeliveryTolerance});e.Subtotal+=amounts.GrossAmount;e.DiscountTotal+=amounts.DiscountAmount;e.TaxTotal+=amounts.TaxAmount;e.GrandTotal+=amounts.GrandTotal;}await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}
[HttpPost("{id:long}/confirm")]public async Task<IActionResult>Confirm(long id,CancellationToken ct){var r=await service.ConfirmAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/cancel")]public async Task<IActionResult>Cancel(long id,CancellationToken ct){var r=await service.CancelAsync(id,ct);return StatusCode(r.StatusCode,r);}
[HttpDelete("{id:long}")]public async Task<IActionResult>Delete(long id,CancellationToken ct){var e=await db.PurchaseOrders.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(e is null)return NotFound(ApiResponse<object>.Error("Purchase order not found.",404));if(e.Status!=PurchaseOrderStatus.Draft)return Conflict(ApiResponse<object>.Error("Only draft purchase orders can be deleted.",409));db.PurchaseOrders.Remove(e);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.Ok(new{e.Id}));}}
